def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            continue
        ratio = item / capacity
        if ratio > 1:
            continue
        score = 0
        coeffs = [0.9, 1.05, 1.2, 0.85, 1.1, 0.95, 1.3, 0.8, 1.15, 1.0, 0.7, 1.25, 0.9, 1.05]
        for j in range(1, 15):
            base = (ratio ** j) / (j**1.5)
            factor = coeffs[j-1]
            if j % 4 == 0:
                factor *= 1.3
            elif j % 5 == 0:
                factor *= 0.9
            if j % 2 == 0 and ratio > 0.7:
                factor += 0.1
            score += base * factor
        remaining = capacity - item
        if remaining < 0.02 * capacity:
            score *= 3
        elif remaining < 0.05 * capacity:
            score *= 2
        elif remaining < 0.15 * capacity:
            score *= 1.3
        elif remaining < 0.25 * capacity:
            score *= 1.0
        else:
            score *= 0.65
        divisors = [2, 3, 5, 7, 11]
        divisor_count = 0
        for d in divisors:
            if int(capacity) % d == 0:
                divisor_count += 1
                score -= 0.04 * (capacity / d)
        if divisor_count == 0:
            score += 0.12 * (capacity / 50)
        penalty = 0
        for k in range(1, 8):
            diff = abs(capacity - item * k)
            threshold = 0.01 * capacity * k
            if diff < threshold:
                penalty += 0.3 * k
            elif diff < 3 * threshold:
                penalty += 0.1 * k
            else:
                penalty -= 0.07 * k
            if diff < 0.005 * capacity:
                penalty += 0.1 * k
        score += penalty
        if score < 0:
            score = 0
        if score > 2:
            for m in range(1, 5):
                if abs((capacity / m) - item) < 0.015 * (capacity / m):
                    score *= (1 + 0.07 * m)
                elif 0.015 * (capacity / m) <= abs((capacity / m) - item) < 0.03 * (capacity / m):
                    score *= (1 + 0.03 * m)
        if item < 0.1 * capacity:
            score *= 0.8
        elif item > 0.9 * capacity:
            score *= 1.2
        if abs(np.sin(capacity)) > 0.9:
            score += 0.1
        priorities[i] = score
    return priorities
